import math

def is_carmichael(n):
    if n<3 or all(n%p for p in range(2,int(n**0.5)+1)):
        return False
    # factor
    m=n
    fac=[]
    p=2
    while p*p<=m:
        if m%p==0:
            c=0
            while m%p==0:
                m//=p; c+=1
            fac.append((p,c))
        p+=1
    if m>1:
        fac.append((m,1))
    # squarefree
    if any(c>1 for _,c in fac):
        return False
    # Korselt divisibility
    for p,_ in fac:
        if (n-1)%(p-1)!=0:
            return False
    return True

print([n for n in range(2,2000) if is_carmichael(n)])

